1	import type { FastifyPluginAsync } from 'fastify';
2	import { z } from 'zod';
3	import { db } from '../db/client.js';
4	import { requireAuth } from '../middleware/auth.js';
5	import type { Artifact, Comment } from '@artifact-hub/types';
6	
7	// ─── DB row shapes ────────────────────────────────────────────────────────────
8	
9	interface DbArtifact {
10	  id: string;
11	  title: string;
12	  description: string | null;
13	  tags: string[];
14	  type: 'html' | 'image' | 'pdf';
15	  storage_url: string;
16	  thumbnail_url: string | null;
17	  author_email: string;
18	  created_at: string;
19	  updated_at: string;
20	}
21	
22	interface DbComment {
23	  id: string;
24	  artifact_id: string;
25	  author_email: string;
26	  body: string;
27	  created_at: string;
28	}
29	
30	// ─── Mappers ──────────────────────────────────────────────────────────────────
31	
32	function toArtifact(row: DbArtifact): Artifact {
33	  return {
34	    id: row.id,
35	    title: row.title,
36	    description: row.description ?? '',
37	    tags: row.tags,
38	    type: row.type,
39	    storageUrl: row.storage_url,
40	    thumbnailUrl: row.thumbnail_url ?? undefined,
41	    authorEmail: row.author_email,
42	    createdAt: row.created_at,
43	    updatedAt: row.updated_at,
44	  };
45	}
46	
47	function toComment(row: DbComment): Comment {
48	  return {
49	    id: row.id,
50	    artifactId: row.artifact_id,
51	    authorEmail: row.author_email,
52	    body: row.body,
53	    createdAt: row.created_at,
54	  };
55	}
56	
57	// ─── Validation schemas ───────────────────────────────────────────────────────
58	
59	const createArtifactFields = z.object({
60	  title: z.string().min(1, 'title is required'),
61	  description: z.string().default(''),
62	  tags: z.string().default(''),           // comma-separated, parsed below
63	  type: z.enum(['html', 'image', 'pdf']),
64	});
65	
66	const listQuery = z.object({
67	  search: z.string().optional(),
68	  tags: z.string().optional(),
69	  type: z.enum(['html', 'image', 'pdf']).optional(),
70	  limit: z.coerce.number().int().min(1).max(100).default(20),
71	  offset: z.coerce.number().int().min(0).default(0),
72	});
73	
74	// ─── Plugin ───────────────────────────────────────────────────────────────────
75	
76	const artifactRoutes: FastifyPluginAsync = async (app) => {
77	
78	  // POST /api/artifacts ───────────────────────────────────────────────────────
79	  app.post('/artifacts', { preHandler: requireAuth }, async (request, reply) => {
80	    const fields: Record<string, string> = {};
81	    let fileBuffer: Buffer | null = null;
82	    let fileName = 'upload';
83	    let fileMimeType = 'application/octet-stream';
84	
85	    // Consume all multipart parts
86	    for await (const part of request.parts()) {
87	      if (part.type === 'file') {
88	        fileBuffer = await part.toBuffer();
89	        fileName = part.filename ?? 'upload';
90	        fileMimeType = part.mimetype;
91	      } else {
92	        fields[part.fieldname] = part.value as string;
93	      }
94	    }
95	
96	    if (!fileBuffer) {
97	      return reply.code(400).send({ error: 'File is required' });
98	    }
99	
100	    const parsed = createArtifactFields.safeParse(fields);
101	    if (!parsed.success) {
102	      return reply.code(400).send({ error: parsed.error.flatten().fieldErrors });
103	    }
104	
105	    const { title, description, tags: tagsRaw, type } = parsed.data;
106	    const tags = tagsRaw
107	      ? tagsRaw.split(',').map((t) => t.trim()).filter(Boolean)
108	      : [];
109	
110	    const user = request.user!;
111	    const storagePath = `${user.id}/${Date.now()}-${fileName}`;
112	
113	    // Upload to Supabase Storage
114	    const { error: uploadError } = await db.storage
115	      .from('artifacts')
116	      .upload(storagePath, fileBuffer, { contentType: fileMimeType, upsert: false });
117	
118	    if (uploadError) {
119	      request.log.error(uploadError, 'Storage upload failed');
120	      return reply.code(500).send({ error: 'File upload failed' });
121	    }
122	
123	    const { data: { publicUrl } } = db.storage
124	      .from('artifacts')
125	      .getPublicUrl(storagePath);
126	
127	    // Insert artifact row
128	    const { data: row, error: dbError } = await db
129	      .from('artifacts')
130	      .insert({
131	        title,
132	        description,
133	        tags,
134	        type,
135	        storage_url: publicUrl,
136	        author_email: user.email,
137	      })
138	      .select()
139	      .single();
140	
141	    if (dbError || !row) {
142	      request.log.error(dbError, 'DB insert failed');
143	      return reply.code(500).send({ error: 'Failed to create artifact' });
144	    }
145	
146	    return reply.code(201).send(toArtifact(row as DbArtifact));
147	  });
148	
149	  // GET /api/artifacts ────────────────────────────────────────────────────────
150	  app.get('/artifacts', async (request, reply) => {
151	    const parsed = listQuery.safeParse(request.query);
152	    if (!parsed.success) {
153	      return reply.code(400).send({ error: parsed.error.flatten().fieldErrors });
154	    }
155	
156	    const { search, tags, type, limit, offset } = parsed.data;
157	
158	    let query = db
159	      .from('artifacts')
160	      .select('*', { count: 'exact' });
161	
162	    if (search) {
163	      query = query.or(`title.ilike.%${search}%,description.ilike.%${search}%`);
164	    }
165	    if (tags) {
166	      const tagArray = tags.split(',').map((t) => t.trim()).filter(Boolean);
167	      if (tagArray.length > 0) {
168	        query = query.contains('tags', tagArray);
169	      }
170	    }
171	    if (type) {
172	      query = query.eq('type', type);
173	    }
174	
175	    const { data, error, count } = await query
176	      .order('created_at', { ascending: false })
177	      .range(offset, offset + limit - 1);
178	
179	    if (error) {
180	      request.log.error(error, 'Failed to list artifacts');
181	      return reply.code(500).send({ error: 'Failed to list artifacts' });
182	    }
183	
184	    return {
185	      artifacts: (data as DbArtifact[]).map(toArtifact),
186	      total: count ?? 0,
187	    };
188	  });
189	
190	  // GET /api/artifacts/:id ────────────────────────────────────────────────────
191	  app.get('/artifacts/:id', async (request, reply) => {
192	    const { id } = request.params as { id: string };
193	
194	    const [artifactResult, commentsResult] = await Promise.all([
195	      db.from('artifacts').select('*').eq('id', id).single(),
196	      db.from('comments').select('*').eq('artifact_id', id).order('created_at', { ascending: true }),
197	    ]);
198	
199	    if (artifactResult.error || !artifactResult.data) {
200	      return reply.code(404).send({ error: 'Artifact not found' });
201	    }
202	
203	    return {
204	      ...toArtifact(artifactResult.data as DbArtifact),
205	      comments: (commentsResult.data ?? []).map((c) => toComment(c as DbComment)),
206	    };
207	  });
208	
209	  // DELETE /api/artifacts/:id ─────────────────────────────────────────────────
210	  app.delete('/artifacts/:id', { preHandler: requireAuth }, async (request, reply) => {
211	    const { id } = request.params as { id: string };
212	    const user = request.user!;
213	
214	    const { data: row, error: fetchError } = await db
215	      .from('artifacts')
216	      .select('*')
217	      .eq('id', id)
218	      .single();
219	
220	    if (fetchError || !row) {
221	      return reply.code(404).send({ error: 'Artifact not found' });
222	    }
223	
224	    if ((row as DbArtifact).author_email !== user.email) {
225	      return reply.code(403).send({ error: 'Forbidden' });
226	    }
