        </p>
      )}

      {/* ── Grid ── */}
      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {loading
          ? Array.from({ length: PAGE_SIZE }).map((_, i) => <SkeletonCard key={i} />)
          : artifacts.map(a => <ArtifactCard key={a.id} artifact={a} />)
        }
      </div>

      {/* Empty state */}
