              {/* Add comment form */}
              <div className="mt-5 border-t border-zinc-800 pt-5">
                {!apiKey ? (
                  <p className="text-xs text-zinc-500">
                    <Link href="/upload" className="text-indigo-400 hover:text-indigo-300">
                      Set your API key
                    </Link>{' '}
