2	
3	const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
4	
5	const MODEL = 'claude-sonnet-4-6';
6	
7	const METADATA_SYSTEM =
8	  'You are helping catalog AI-generated content. Analyze this artifact and return ONLY a JSON object with: ' +
9	  'title (concise, max 60 chars), description (2-3 sentences about what this is), ' +
10	  'tags (array of 3-6 lowercase relevant tags). No markdown, no preamble, just JSON.';
11	
12	// ─── Helpers ──────────────────────────────────────────────────────────────────
13	
14	function stripHtmlTags(html: string): string {
15	  return html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
16	}
17	
18	function safeImageMediaType(
19	  mimeType: string,
20	): 'image/jpeg' | 'image/png' | 'image/gif' | 'image/webp' {
21	  const allowed = new Set(['image/jpeg', 'image/png', 'image/gif', 'image/webp']);
22	  return allowed.has(mimeType)
23	    ? (mimeType as 'image/jpeg' | 'image/png' | 'image/gif' | 'image/webp')
24	    : 'image/jpeg';
25	}
26	
27	// ─── generateMetadata ─────────────────────────────────────────────────────────
28	
29	export interface ArtifactMetadata {
30	  title: string;
31	  description: string;
32	  tags: string[];
33	}
34	
35	export async function generateMetadata(
36	  fileBuffer: Buffer,
37	  fileType: string,
38	  filename: string,
39	): Promise<ArtifactMetadata> {
40	  const fallback: ArtifactMetadata = { title: filename, description: '', tags: [] };
41	
42	  try {
43	    let message: Anthropic.MessageParam;
44	
45	    if (fileType === 'image') {
46	      message = {
47	        role: 'user',
48	        content: [
49	          {
50	            type: 'image',
51	            source: {
52	              type: 'base64',
53	              media_type: safeImageMediaType(
54	                filename.toLowerCase().endsWith('.png') ? 'image/png'
55	                  : filename.toLowerCase().endsWith('.gif') ? 'image/gif'
56	                  : filename.toLowerCase().endsWith('.webp') ? 'image/webp'
57	                  : 'image/jpeg',
58	              ),
59	              data: fileBuffer.toString('base64'),
60	            },
61	          },
62	          { type: 'text', text: 'Analyze this image artifact.' },
63	        ],
64	      };
65	    } else {
66	      let text: string;
67	      if (fileType === 'html') {
68	        text = stripHtmlTags(fileBuffer.toString('utf-8')).slice(0, 3000);
69	      } else {
70	        // pdf — decode first 3000 bytes as latin-1 to preserve byte values
71	        text = fileBuffer.slice(0, 3000).toString('latin1');
72	      }
73	      message = {
74	        role: 'user',
75	        content: `Analyze this ${fileType} artifact:\n\n${text}`,
76	      };
77	    }
78	
79	    const response = await client.messages.create({
80	      model: MODEL,
81	      max_tokens: 256,
82	      system: METADATA_SYSTEM,
83	      messages: [message],
84	    });
85	
86	    const raw = response.content
87	      .filter((b): b is Anthropic.TextBlock => b.type === 'text')
88	      .map((b) => b.text)
89	      .join('');
90	
91	    const parsed = JSON.parse(raw) as Partial<ArtifactMetadata>;
92	
93	    return {
94	      title: typeof parsed.title === 'string' ? parsed.title.slice(0, 60) : fallback.title,
95	      description: typeof parsed.description === 'string' ? parsed.description : '',
96	      tags: Array.isArray(parsed.tags)
97	        ? parsed.tags.filter((t): t is string => typeof t === 'string')
98	        : [],
99	    };
100	  } catch {
101	    return fallback;
102	  }
103	}
104	
105	// ─── summarizeFeedback ────────────────────────────────────────────────────────
106	
107	export async function summarizeFeedback(
108	  artifactTitle: string,
109	  comments: { authorEmail: string; body: string; createdAt: string }[],
110	): Promise<string> {
111	  if (comments.length === 0) return 'No feedback yet.';
112	
113	  const commentList = comments
114	    .map((c, i) => `${i + 1}. [${c.authorEmail} at ${c.createdAt}]: ${c.body}`)
115	    .join('\n');
116	
117	  const prompt =
118	    `You are summarizing reviewer feedback on an AI-generated artifact titled '${artifactTitle}'. ` +
119	    `Here are all comments:\n${commentList}\n\n` +
120	    `Write a 2-3 sentence neutral summary of the overall feedback, key themes, and any action items mentioned. ` +
121	    `Be concise and specific.`;
122	
123	  try {
124	    const response = await client.messages.create({
125	      model: MODEL,
126	      max_tokens: 256,
127	      messages: [{ role: 'user', content: prompt }],
128	    });
129	
130	    return response.content
131	      .filter((b): b is Anthropic.TextBlock => b.type === 'text')
132	      .map((b) => b.text)
133	      .join('')
134	      .trim();
135	  } catch {
136	    return 'Unable to generate summary at this time.';
137	  }
138	}
