1	/**
2	 * Seed script — populates the gallery with demo data so reviewers see a
3	 * working product immediately.
4	 *
5	 * Usage (from repo root, after starting the API):
6	 *   pnpm seed
7	 */
8	
9	import 'dotenv/config';
10	
11	const API_URL = (
12	  process.env.NEXT_PUBLIC_API_URL ??
13	  process.env.API_BASE_URL ??
14	  'http://localhost:3001'
15	).replace(/\/$/, '');
16	
17	const API_KEY = process.env.API_KEY ?? 'demo-api-key-12345';
18	const DEMO_EMAIL = 'demo@artifacthub.com';
19	
20	// ─── Sample artifacts ─────────────────────────────────────────────────────────
21	
22	const SAMPLES = [
23	  {
24	    picsum: 'https://picsum.photos/seed/mountains/800/600',
25	    filename: 'mountains.jpg',
26	    type: 'image',
27	    title: 'Mountain Landscape',
28	    description: 'A serene mountain landscape generated for demonstration purposes.',
29	    tags: 'landscape,nature,mountains,demo',
30	  },
31	  {
32	    picsum: 'https://picsum.photos/seed/cityscape/800/600',
33	    filename: 'cityscape.jpg',
34	    type: 'image',
35	    title: 'Urban Cityscape',
36	    description: 'A vibrant cityscape showcasing modern architecture.',
37	    tags: 'city,urban,architecture,demo',
38	  },
39	  {
40	    picsum: 'https://picsum.photos/seed/forest/800/600',
41	    filename: 'forest.jpg',
42	    type: 'image',
43	    title: 'Forest Path',
44	    description: 'A tranquil forest path with dappled light through the canopy.',
45	    tags: 'forest,nature,trees,demo',
46	  },
47	] as const;
48	
49	const SAMPLE_COMMENTS = [
50	  'Great composition — the lighting feels very natural.',
51	  'This would work well as a hero image. Consider a slightly warmer tone.',
52	];
53	
54	// ─── HTTP helper ──────────────────────────────────────────────────────────────
55	
56	async function api<T>(
57	  method: string,
58	  path: string,
59	  body?: FormData | Record<string, unknown>,
60	): Promise<T> {
61	  const headers: Record<string, string> = { 'x-api-key': API_KEY };
62	  let fetchBody: FormData | string | undefined;
63	
64	  if (body instanceof FormData) {
65	    fetchBody = body;
66	  } else if (body) {
67	    headers['content-type'] = 'application/json';
68	    fetchBody = JSON.stringify(body);
69	  }
70	
71	  const res = await fetch(`${API_URL}${path}`, { method, headers, body: fetchBody });
72	  if (res.status === 204) return undefined as T;
73	
74	  const data = await res.json().catch(() => ({ error: res.statusText })) as Record<string, unknown>;
75	  if (!res.ok) {
76	    throw new Error(String(data['error'] ?? `HTTP ${res.status}`));
77	  }
78	  return data as T;
79	}
80	
81	// ─── Steps ────────────────────────────────────────────────────────────────────
82	
83	async function checkHealth(): Promise<void> {
84	  try {
85	    const res = await fetch(`${API_URL}/health`);
86	    if (!res.ok) throw new Error(`${res.status}`);
87	  } catch (err) {
88	    console.error(`\n✗ API unreachable at ${API_URL}`);
89	    console.error('  Start the server first:  pnpm dev\n');
90	    process.exit(1);
91	  }
92	  console.log(`✓ API is up at ${API_URL}`);
93	}
94	
95	async function ensureDemoUser(): Promise<void> {
96	  try {
97	    await api('POST', '/api/users', { email: DEMO_EMAIL });
98	    console.log(`✓ Created demo user: ${DEMO_EMAIL}`);
99	  } catch (err) {
100	    const msg = (err as Error).message;
101	    if (msg.toLowerCase().includes('already') || msg.includes('409')) {
102	      console.log(`✓ Demo user already exists: ${DEMO_EMAIL}`);
103	    } else {
104	      throw err;
105	    }
106	  }
107	}
108	
109	async function uploadArtifact(sample: (typeof SAMPLES)[number]): Promise<string> {
110	  console.log(`  Downloading ${sample.filename}…`);
111	  const imgRes = await fetch(sample.picsum);
112	  if (!imgRes.ok) throw new Error(`Failed to download ${sample.picsum}: ${imgRes.status}`);
113	
114	  const buffer = Buffer.from(await imgRes.arrayBuffer());
115	  const contentType = imgRes.headers.get('content-type') ?? 'image/jpeg';
116	
117	  const form = new FormData();
118	  form.append('file', new Blob([buffer], { type: contentType }), sample.filename);
119	  form.append('type', sample.type);
120	  form.append('title', sample.title);
121	  form.append('description', sample.description);
122	  form.append('tags', sample.tags);
123	
124	  const artifact = await api<{ id: string; title: string }>('POST', '/api/artifacts', form);
125	  console.log(`  ✓ Uploaded "${artifact.title}" (id: ${artifact.id})`);
126	  return artifact.id;
127	}
128	
129	async function addComment(artifactId: string, body: string): Promise<void> {
130	  await api('POST', `/api/artifacts/${artifactId}/comments`, { body });
131	  console.log(`  ✓ Comment added`);
132	}
133	
134	// ─── Main ─────────────────────────────────────────────────────────────────────
135	
136	async function main(): Promise<void> {
137	  console.log('\n── Artifact Hub seed ─────────────────────────\n');
138	
139	  await checkHealth();
140	  await ensureDemoUser();
141	
142	  console.log('\nUploading sample artifacts…');
143	  const ids: string[] = [];
144	  for (const sample of SAMPLES) {
145	    const id = await uploadArtifact(sample);
146	    ids.push(id);
147	  }
148	
149	  const firstId = ids[0];
150	  if (firstId) {
151	    console.log(`\nAdding sample comments to first artifact (${firstId})…`);
152	    for (const body of SAMPLE_COMMENTS) {
153	      await addComment(firstId, body);
154	    }
155	  }
156	
157	  console.log('\n── Done ──────────────────────────────────────');
158	  console.log(`\nOpen ${process.env.NEXT_PUBLIC_API_URL?.replace('3001', '3000') ?? 'http://localhost:3000'} to see the gallery.\n`);
159	}
160	
161	main().catch(err => {
162	  console.error('\n✗ Seed failed:', (err as Error).message);
163	  process.exit(1);
164	});
165

