import type { Metadata } from 'next';
import { Providers } from '@/components/Providers';
import { Navbar } from '@/components/Navbar';
import './globals.css';

export const metadata: Metadata = {
  title: { default: 'Artifact Hub', template: '%s — Artifact Hub' },
  description: 'Browse and share AI-generated content',
};

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <body className="min-h-screen bg-[#0a0a0a] text-zinc-100 antialiased">
        <Providers>
          <Navbar />
          {/* Push content below the fixed navbar */}
          <div className="pt-14">{children}</div>
        </Providers>
      </body>
    </html>
  );
}

import Link from 'next/link';

export function Navbar() {
  return (
    <header className="fixed inset-x-0 top-0 z-40 border-b border-zinc-800/60 bg-[#0a0a0a]/80 backdrop-blur-xl">
      <div className="mx-auto flex h-14 max-w-7xl items-center justify-between px-4 sm:px-6 lg:px-8">
        {/* Logo */}
        <Link
          href="/"
