'use client';

import { createContext, useContext, useEffect, useState } from 'react';
import { getStoredApiKey, storeApiKey } from '@/lib/api';

interface ApiKeyContextValue {
  apiKey: string;
  setApiKey: (key: string) => void;
}

const ApiKeyContext = createContext<ApiKeyContextValue>({ apiKey: '', setApiKey: () => {} });

export function ApiKeyProvider({ children }: { children: React.ReactNode }) {
  const [apiKey, setApiKeyState] = useState('');

  // Hydrate from localStorage after mount (avoids SSR mismatch)
  useEffect(() => {
    setApiKeyState(getStoredApiKey());
  }, []);

  function setApiKey(key: string) {
    const trimmed = key.trim();
    setApiKeyState(trimmed);
    storeApiKey(trimmed);
  }

  return (
    <ApiKeyContext.Provider value={{ apiKey, setApiKey }}>
      {children}
    </ApiKeyContext.Provider>
  );
}

export function useApiKey() {
  return useContext(ApiKeyContext);
}

export function SkeletonCard() {
  return (
    <div className="flex h-full flex-col rounded-xl border border-zinc-800 bg-zinc-900 p-5">
      {/* Badge + date */}
      <div className="flex items-center justify-between gap-2">
        <div className="h-5 w-12 animate-pulse rounded-md bg-zinc-800" />
        <div className="h-4 w-20 animate-pulse rounded bg-zinc-800" />
      </div>
      {/* Title */}
      <div className="mt-3 space-y-1.5">
        <div className="h-4 w-full animate-pulse rounded bg-zinc-800" />
        <div className="h-4 w-3/4 animate-pulse rounded bg-zinc-800" />
      </div>
      {/* Description */}
      <div className="mt-2 space-y-1">
        <div className="h-3 w-full animate-pulse rounded bg-zinc-800" />
        <div className="h-3 w-5/6 animate-pulse rounded bg-zinc-800" />
      </div>
      {/* Tags */}
      <div className="mt-auto flex gap-1 pt-4">
        <div className="h-5 w-12 animate-pulse rounded-md bg-zinc-800" />
        <div className="h-5 w-16 animate-pulse rounded-md bg-zinc-800" />
        <div className="h-5 w-10 animate-pulse rounded-md bg-zinc-800" />
      </div>
    </div>
  );
}

