import { readFileSync, writeFileSync, unlinkSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const dir = dirname(fileURLToPath(import.meta.url));

const filesToCheck = [
  join(dir, 'src/app/global-error.tsx'),
  join(dir, 'src/app/layout.tsx'),
  join(dir, 'src/app/page.tsx'),
  join(dir, 'src/app/not-found.tsx'),
];

for (const f of filesToCheck) {
  const buf = readFileSync(f);
  const hasBOM = buf[0] === 0xEF && buf[1] === 0xBB && buf[2] === 0xBF;
  const name = f.split(/[\\/]/).pop();
  console.log(`${name}: bytes[0..2] = ${buf[0]} ${buf[1]} ${buf[2]} — ${hasBOM ? 'HAS BOM, stripping' : 'clean'}`);
  if (hasBOM) {
    writeFileSync(f, buf.slice(3));
    console.log(`  -> stripped BOM from ${name}`);
  }
}

unlinkSync(join(dir, 'check-bom.mjs'));
console.log('Done');

